export async function cancelOrder(db, id, reason){
  // BUG: no version check, last write wins
  await db.query(
    'UPDATE orders SET status=$1, cancel_reason=$2, updated_at=now() WHERE id=$3',
    ['cancelled', reason, id]
  );
}

export async function shipOrder(db, id, tracking){
  await db.query(
    'UPDATE orders SET status=$1, tracking=$2, updated_at=now() WHERE id=$3',
    ['shipped', tracking, id]
  );
}

router.post('/orders/:id/cancel', async (req,res)=>{
  await cancelOrder(req.db, req.params.id, req.body.reason);
  res.json({ ok: true }); // returns before reading back; client may see stale row
});

export type OrderEvent =
  | { type:'OrderPlaced'; total:number }
  | { type:'OrderShipped'; tracking:string }
  | { type:'OrderCancelled'; reason:string };

export interface OrderState { status:'placed'|'shipped'|'cancelled'; version:number; total:number }

export function fold(state:OrderState|null, e:OrderEvent):OrderState {
  switch(e.type){
    case 'OrderPlaced': return { status:'placed', version:1, total:e.total };
    case 'OrderShipped': return { ...state!, status:'shipped', version:state!.version+1 };
    case 'OrderCancelled': return { ...state!, status:'cancelled', version:state!.version+1 };
  }
}

export function cancel(state:OrderState, reason:string):OrderEvent {
  if(state.status==='shipped') throw new IllegalTransition('cannot cancel shipped order');
  if(state.status==='cancelled') throw new IllegalTransition('already cancelled');
  return { type:'OrderCancelled', reason };
}

export async function append(db, orderId, expectedVersion, event){
  // unique (order_id, version) gives optimistic concurrency control
  try {
    await db.query(
      'INSERT INTO order_events(order_id, version, type, data) VALUES($1,$2,$3,$4)',
      [orderId, expectedVersion+1, event.type, event]
    );
  } catch(err){
    if(err.code==='23505') throw new ConcurrencyError(orderId, expectedVersion);
    throw err;
  }
}

export async function load(db, orderId){
  const { rows } = await db.query(
    'SELECT type, data FROM order_events WHERE order_id=$1 ORDER BY version', [orderId]);
  return rows.reduce((s,r)=>fold(s, r.data), null);
}

router.post('/orders/:id/cancel', async (req,res)=>{
  const state = await load(req.db, req.params.id);
  if(!state) return res.status(404).end();
  try {
    const ev = cancel(state, req.body.reason);
    await append(req.db, req.params.id, state.version, ev);
  } catch(e){
    if(e instanceof ConcurrencyError) return res.status(409).json({retry:true});
    if(e instanceof IllegalTransition) return res.status(422).json({error:e.message});
    throw e;
  }
  res.json(await load(req.db, req.params.id));
});

export async function project(db, batch){
  for(const e of batch){
    const state = await load(db, e.order_id);
    await db.query(
      `INSERT INTO order_read(id,status,total,version) VALUES($1,$2,$3,$4)
       ON CONFLICT(id) DO UPDATE SET status=$2,total=$3,version=$4 WHERE order_read.version < $4`,
      [e.order_id, state.status, state.total, state.version]);
  }
}

export async function loadWallet(db, walletId){
  const { rows } = await db.query(
    'SELECT data FROM wallet_events WHERE wallet_id=$1 ORDER BY version', [walletId]);
  // folds ALL events every time -> O(n) per auth
  return rows.reduce((s,r)=>apply(s, r.data), { balance:0, version:0 });
}

export async function loadWallet(db, walletId){
  const snap = await db.query(
    'SELECT state, version, schema_v FROM wallet_snapshots WHERE wallet_id=$1 ORDER BY version DESC LIMIT 1',[walletId]);
  let state = snap.rows[0] ? migrate(snap.rows[0]) : { balance:0, version:0 };
  const { rows } = await db.query(
    'SELECT data, version FROM wallet_events WHERE wallet_id=$1 AND version>$2 ORDER BY version',
    [walletId, state.version]);
  for(const r of rows) state = apply(state, r.data);
  return state;
}

const SNAPSHOT_EVERY = 500;
export async function maybeSnapshot(db, walletId, state){
  if(state.version % SNAPSHOT_EVERY !== 0) return;
  await db.query(
    `INSERT INTO wallet_snapshots(wallet_id, version, state, schema_v)
     VALUES($1,$2,$3,$4) ON CONFLICT(wallet_id, version) DO NOTHING`,
    [walletId, state.version, state, CURRENT_SCHEMA_V]);
}

export function migrate(row){
  let s = row.state;
  if(row.schema_v < 2){ s = { ...s, pendingHolds: s.pendingHolds ?? [] }; }
  return { ...s, version: row.version };
}

export async function onEvent(db, e){
  const delta = e.type==='PostLiked' ? 1 : -1;
  // BUG: redelivered event re-applies delta
  await db.query('UPDATE like_counts SET n=n+$1 WHERE post_id=$2', [delta, e.postId]);
  await commitOffset(e); // offset committed AFTER db write but not atomic with it
}

export async function onBatch(db, events){
  for(const e of events){
    await db.tx(async tx=>{
      const ins = await tx.query(
        'INSERT INTO processed_events(event_id) VALUES($1) ON CONFLICT DO NOTHING RETURNING 1',
        [e.eventId]);
      if(ins.rowCount===0) return; // already applied -> skip delta
      const delta = e.type==='PostLiked' ? 1 : -1;
      await tx.query(
        'INSERT INTO like_counts(post_id,n) VALUES($1,$2) ON CONFLICT(post_id) DO UPDATE SET n=like_counts.n+$2',
        [e.postId, delta]);
    });
  }
}

CREATE TABLE processed_events(
  event_id uuid PRIMARY KEY,
  applied_at timestamptz DEFAULT now()
) PARTITION BY HASH (event_id);
CREATE TABLE processed_events_p0 PARTITION OF processed_events FOR VALUES WITH (MODULUS 8, REMAINDER 0);
-- ... p1..p7
CREATE INDEX ON like_counts(post_id);

export async function rebuild(db, fromOffset=0){
  await db.query('TRUNCATE like_counts');
  await db.query('TRUNCATE processed_events');
  await consumeFrom(fromOffset, batch=>onBatch(db, batch));
}
